{
    "level": "A2–B1",
    "intro": "W tym temacie nauczysz się budować <strong>subject questions</strong> — pytania o osobę albo rzecz, która <strong>wykonuje czynność</strong>.",
    "rules": [
        {
            "label": "WHO / WHAT JAKO SUBJECT",
            "color": "emerald",
            "text": "Gdy <strong>who</strong> albo <strong>what</strong> jest podmiotem, stoi samo na pozycji subject:",
            "example": "Who called you? / What happened?"
        },
        {
            "label": "BEZ DO / DOES / DID",
            "color": "blue",
            "text": "W zwykłym subject question <strong>nie dodajemy do / does / did</strong>.",
            "example": "Who lives here? not Who does live here?"
        },
        {
            "label": "OBJECT QUESTION = INACZEJ",
            "color": "amber",
            "text": "Jeśli słowo pytające nie jest podmiotem, mamy <strong>object question</strong> i często potrzebny jest operator.",
            "example": "Who called you? vs Who did you call?"
        }
    ]
}

{
    "title": "1. Podstawowy schemat",
    "intro": "Porównaj subject questions i object questions.",
    "items": [
        {
            "label": "Subject question",
            "title": "Who called you?",
            "subtitle": "who = podmiot, bez did"
        },
        {
            "label": "Object question",
            "title": "Who did you call?",
            "subtitle": "who = dopełnienie, potrzebne did"
        },
        {
            "label": "Główna formuła",
            "title": "Who / What + verb + ...?",
            "subtitle": "Who wants coffee? / What caused the problem?"
        },
        {
            "label": "Najważniejsza zasada",
            "title": "no inversion, no do-support",
            "subtitle": "szyk jest bliższy zdaniu oznajmującemu"
        }
    ]
}

{
    "title": "2. Jak działają subject questions",
    "sections": [
        {
            "label": "Who jako podmiot",
            "color": "emerald",
            "description": "Gdy nie wiemy, <strong>która osoba</strong> wykonała czynność, używamy <strong>who</strong> jako subject.",
            "examples": [
                {
                    "en": "Who called you last night?",
                    "ua": "Kto zadzwonił do ciebie wczoraj wieczorem?"
                },
                {
                    "en": "Who lives in that house?",
                    "ua": "Kto mieszka w tym domu?"
                },
                {
                    "en": "Who wants some tea?",
                    "ua": "Kto chce herbaty?"
                }
            ]
        },
        {
            "label": "What jako podmiot",
            "color": "blue",
            "description": "Gdy pytamy o <strong>rzecz, wydarzenie albo przyczynę</strong>, która jest podmiotem, używamy <strong>what</strong>.",
            "examples": [
                {
                    "en": "What happened?",
                    "ua": "Co się stało?"
                },
                {
                    "en": "What made you laugh?",
                    "ua": "Co cię rozśmieszyło?"
                },
                {
                    "en": "What caused the delay?",
                    "ua": "Co spowodowało opóźnienie?"
                }
            ]
        },
        {
            "label": "Kontrast z object questions",
            "color": "amber",
            "description": "Zadaj sobie pytanie: <strong>kto wykonuje czynność</strong> czy <strong>na kogo ona jest skierowana</strong>? To decyduje o strukturze.",
            "examples": [
                {
                    "en": "Who called you?",
                    "ua": "Kto do ciebie zadzwonił?"
                },
                {
                    "en": "Who did you call?",
                    "ua": "Do kogo zadzwoniłeś?"
                },
                {
                    "en": "What broke the window?",
                    "ua": "Co rozbiło okno?"
                },
                {
                    "en": "What did you break?",
                    "ua": "Co rozbiłeś?"
                }
            ],
            "note": "Jeśli wh-word jest podmiotem, nie dodajemy do / does / did."
        }
    ]
}

{
    "title": "3. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Dodawanie do / does / did w subject question.",
            "wrong": "Who did call you?",
            "right": "✅ <span class=\"font-mono\">Who called you?</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Mylenie subject question z object question.",
            "wrong": "Who called you? = osoba, do której zadzwoniłeś",
            "right": "✅ <span class=\"font-mono\">Who did you call?</span> = osoba, do której zadzwoniłeś"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Inwersja po what.",
            "wrong": "What did happen?",
            "right": "✅ <span class=\"font-mono\">What happened?</span>"
        }
    ]
}

